// Extract and validate input
const body = $input.item.json.body || $input.item.json;
const topic = body.topic;
const executionId = body.executionId;

if (!topic || !executionId) {
  throw new Error('Missing required fields: topic and executionId');
}

return {
  json: {
    topic,
    executionId,
    timestamp: new Date().toISOString()
  }
};

parameters.text:
=You are a research orchestrator. Analyze these search queries and retrieve relevant academic papers.

Topic: {{ $json.topic }}
Queries: {{ $json.queries }}

For each query, search academic databases and return:
1. Paper titles
2. Authors
3. Abstracts
4. Publication year
5. Citation count
6. Quality score (0-100)

Return JSON format:
{
  "papers": [
    {
      "title": "...",
      "authors": ["..."],
      "abstract": "...",
      "year": 2024,
      "citations": 50,
      "qualityScore": 85
    }
  ]
}

parameters.functionCode:
// Parse LLM1 response
const message = $input.item.json.message;
const content = message?.content || message || '';
let queries;

try {
  queries = JSON.parse(content);
  if (!Array.isArray(queries)) {
    queries = [content];
  }
} catch (e) {
  queries = [$input.first().json.topic];
}

return {
  json: {
    topic: $input.first().json.topic,
    executionId: $input.first().json.executionId,
    queries: queries
  }
};

// Parse LLM2 response and extract papers
const message = $input.item.json.message;
const content = message?.content || message || '';
let result;

try {
  result = JSON.parse(content);
} catch (e) {
  result = { papers: [] };
}

const papers = result.papers || [];

// Calculate average quality score
const avgQuality = papers.length > 0 
  ? papers.reduce((sum, p) => sum + (p.qualityScore || 0), 0) / papers.length
  : 0;

return {
  json: {
    topic: $input.first().json.topic,
    executionId: $input.first().json.executionId,
    papers: papers,
    averageQuality: avgQuality,
    passesThreshold: avgQuality > 75
  }
};

// Format final survey from LLM3 + Prompt
const message = $input.item.json.message;
const content = message?.content || message || '';
let survey;

try {
  survey = JSON.parse(content);
} catch (e) {
  survey = {
    introduction: 'Survey generation in progress...',
    mainContent: '',
    conclusion: ''
  };
}

const papers = $input.first().json.papers || [];
const references = papers.map(p => ({
  title: p.title,
  authors: p.authors,
  year: p.year
}));

return {
  json: {
    executionId: $input.first().json.executionId,
    topic: $input.first().json.topic,
    content: survey,
    references: references,
    metadata: {
      paperCount: papers.length,
      averageQuality: $input.first().json.averageQuality,
      generatedAt: new Date().toISOString(),
      qualityTier: 'high'
    }
  }
};

// Create basic survey for lower quality papers
const papers = $json.papers || [];
const topic = $json.topic;

const basicSurvey = {
  introduction: `This is a literature survey on ${topic}. Based on available research papers, we present the following findings.`,
  mainContent: papers.map(p => `${p.title} (${p.year}): ${p.abstract}`).join('\n\n'),
  conclusion: 'Further research is needed in this area to provide more comprehensive insights.'
};

const references = papers.map(p => ({
  title: p.title,
  authors: p.authors,
  year: p.year
}));

return {
  json: {
    executionId: $json.executionId,
    topic: $json.topic,
    content: basicSurvey,
    references: references,
    metadata: {
      paperCount: papers.length,
      averageQuality: $json.averageQuality,
      generatedAt: new Date().toISOString(),
      qualityTier: 'standard'
    }
  }
};
